pure fn add_service(amount: Number, rate: Number) -> Number {
    return amount + amount * rate
}
pure fn add_vat(amount: Number, rate: Number) -> Number {
    return amount + amount * rate
}
pure fn split_evenly(total: Number, n: Number) -> Number {
    return total / n
}
entry main(x: Text) {
    base = 30000
    after_service = add_service(base, 0.10)
    after_vat = add_vat(after_service, 0.10)
    per_person = split_evenly(after_vat, 4)
    return to_text(per_person)
}

pure fn apply_pct_discount(price: Number, rate: Number) -> Number {
    return price - price * rate
}
pure fn apply_coupon(price: Number, coupon: Number) -> Number {
    return price - coupon
}
pure fn apply_vat(price: Number, rate: Number) -> Number {
    return price + price * rate
}
entry main(x: Text) {
    base = 50000
    after_member = apply_pct_discount(base, 0.10)
    after_coupon = apply_coupon(after_member, 5000)
    final_price = apply_vat(after_coupon, 0.10)
    return to_text(final_price)
}

pure fn end_hour(start: Number, duration: Number) -> Number {
    return (start + duration) % 24
}
entry main(x: Text) {
    return to_text(end_hour(9, 26))
}

pure fn convert_to_krw(usd: Number, rate: Number) -> Number {
    return usd * rate
}
pure fn ceil_to_unit(amount: Number, unit: Number) -> Number {
    return ceil(amount / unit) * unit
}
entry main(x: Text) {
    krw = convert_to_krw(87.5, 1340)
    rounded = ceil_to_unit(krw, 100)
    return to_text(rounded)
}

pure fn sum_of(scores: Text) -> Number {
    total = 0
    for s in scores { total = total + s }
    return total
}
pure fn avg_drop_lowest(scores: Text) -> Number {
    lowest = min(scores)
    total = sum_of(scores)
    n = length(scores) - 1
    return (total - lowest) / n
}
entry main(x: Text) {
    scores = [85, 92, 78, 95, 88]
    return to_text(avg_drop_lowest(scores))
}

pure fn dinner_share(total: Number, n: Number) -> Number {
    return total / n
}
pure fn shared_dish_share(total: Number, n_lunch: Number) -> Number {
    return total / n_lunch
}
pure fn person_total(dinner: Number, own_lunch: Number, shared: Number) -> Number {
    return dinner + own_lunch + shared
}
entry main(x: Text) {
    sanghyun_dinner = dinner_share(213000, 5)
    sanghyun_own_lunch = 14000
    sanghyun_kimchijeon = shared_dish_share(18000, 4)
    return to_text(person_total(sanghyun_dinner, sanghyun_own_lunch, sanghyun_kimchijeon))
}

pure fn share_among(total: Number, n: Number) -> Number {
    return total / n
}
entry main(x: Text) {
    yeonghee_group_photo = 0
    yeonghee_individual = 12000
    yeonghee_souvenir = share_among(24000, 5)
    return to_text(yeonghee_group_photo + yeonghee_individual + yeonghee_souvenir)
}

pure fn gas_share(car_gas: Number, n_in_car: Number) -> Number {
    return car_gas / n_in_car
}
pure fn dinner_share(total: Number, n_total: Number) -> Number {
    return total / n_total
}
entry main(x: Text) {
    sanghyun_gas = gas_share(80000, 4)
    sanghyun_dinner = dinner_share(140000, 7)
    return to_text(sanghyun_gas + sanghyun_dinner)
}

pure fn drink_share(total: Number, n_total: Number) -> Number {
    return total / n_total
}
pure fn adult_per_share(adult_price: Number, drink_per: Number) -> Number {
    return adult_price + drink_per
}
entry main(x: Text) {
    drink_per = drink_share(60000, 6)
    return to_text(adult_per_share(50000, drink_per))
}

pure fn night_share(total: Number, n: Number) -> Number {
    return total / n
}
entry main(x: Text) {
    yeonghee_night1 = night_share(200000, 5)
    yeonghee_night2 = night_share(100000, 2)
    return to_text(yeonghee_night1 + yeonghee_night2)
}

pure fn simple_total(unit: Number, count: Number) -> Number {
    return unit * count
}
pure fn bogo_total(unit: Number, count: Number) -> Number {
    return unit * (count / 2)
}
pure fn apply_discount(total: Number, rate: Number) -> Number {
    return total - total * rate
}
entry main(x: Text) {
    ramen = simple_total(1500, 5)
    gimbap = simple_total(3500, 3)
    drinks = bogo_total(1800, 6)
    subtotal = ramen + gimbap + drinks
    return to_text(apply_discount(subtotal, 0.05))
}

pure fn parse_row(line: Text) -> Text {
    parts = split(line, ":")
    if length(parts) < 2 { return error("malformed") }
    amount = to_number(get(parts, 1))
    if is_error(amount) { return error("bad amount") }
    return ok([get(parts, 0), unwrap(amount)])
}
pure fn category_total(rows: Text, category: Text) -> Number {
    total = 0
    for row in rows {
        if get(row, 0) == category { total = total + get(row, 1) }
    }
    return total
}
intent saving_tip(category_won: Number) -> Text {
    goal: one short Korean line on whether this weekly food spend is reasonable
}
entry main(text: Text) {
    raw_lines = split(text, "\n")
    parsed = []
    for line in raw_lines {
        r = parse_row(line)
        if is_ok(r) { parsed = append(parsed, unwrap(r)) }
    }
    food = category_total(parsed, "식비")
    advice = saving_tip(food)
    return join([to_text(food), "원 식비 / ", advice], "")
}

pure fn tip_rate(rating: Number) -> Number {
    if rating <= 2 { return 0.0 }
    if rating == 3 { return 0.05 }
    if rating == 4 { return 0.10 }
    return 0.15
}
pure fn add_tip(amount: Number, rate: Number) -> Number {
    return amount + amount * rate
}
pure fn split_evenly(total: Number, n: Number) -> Number {
    return total / n
}
intent budget_opinion(per_person: Number) -> Text {
    goal: one Korean line on whether this lunch cost per person is reasonable
}
entry main(x: Text) {
    rate = tip_rate(4)
    with_tip = add_tip(32000, rate)
    per = split_evenly(with_tip, 4)
    op = budget_opinion(per)
    return join([to_text(per), "원/인 — ", op], "")
}

pure fn bmi(h_cm: Number, w_kg: Number) -> Number {
    h_m = h_cm / 100
    return w_kg / (h_m * h_m)
}
pure fn avg(xs: Text) -> Number {
    total = 0
    for x in xs { total = total + x }
    return total / length(xs)
}
pure fn index_of(xs: Text, target: Number) -> Number {
    i = 0
    for x in xs {
        if x == target { return i }
        i = i + 1
    }
    return -1
}
intent group_health(avg_bmi: Number) -> Text {
    goal: one Korean line evaluating group health from average BMI
}
entry main(x: Text) {
    heights = [175, 160, 180, 170, 165]
    weights = [70, 55, 90, 65, 60]
    bmis = []
    i = 0
    for h in heights {
        bmis = append(bmis, bmi(h, weights[i]))
        i = i + 1
    }
    a = avg(bmis)
    top_idx = index_of(bmis, max(bmis))
    advice = group_health(a)
    return join(["top idx ", to_text(top_idx), " / avg ", to_text(round(a, 1)), " — ", advice], "")
}

pure fn usd_to_krw(usd: Number, rate: Number) -> Number {
    return usd * rate
}
pure fn krw_to_usd(krw: Number, rate: Number) -> Number {
    return krw / rate
}
intent week_budget_opinion(remaining_usd: Number) -> Text {
    goal: one Korean line judging whether this remaining USD budget covers a week of travel comfortably
}
entry main(x: Text) {
    budget_krw = usd_to_krw(1500, 1340)
    after_flight = budget_krw - 1340000
    remaining_usd = krw_to_usd(after_flight, 1340)
    op = week_budget_opinion(remaining_usd)
    return join(["remaining ", to_text(remaining_usd), " USD — ", op], "")
}

pure fn end_hour(start_hour: Number, dur_hours: Number, dur_mins: Number) -> Number {
    total_min = start_hour * 60 + dur_hours * 60 + dur_mins
    end_min = total_min % (24 * 60)
    return floor(end_min / 60)
}
pure fn is_overtime(hour: Number) -> Boolean {
    return hour >= 20
}
intent meeting_opinion(duration_hours: Number) -> Text {
    goal: one Korean line evaluating whether this meeting length is healthy
}
entry main(x: Text) {
    end = end_hour(15, 6, 30)
    overtime = is_overtime(end)
    op = meeting_opinion(6.5)
    return join(["end ", to_text(end), "h / overtime=", to_text(overtime), " — ", op], "")
}
